	('d0000000-0000-0000-0000-000000000019', '{"ar": "الطاقة الشمسية لمواقع الاتصالات", "en": "Solar energy for telecom sites", "fr": "Energie solaire pour les sites télécoms", "pt": "Energia solar para sites de telecomunicações"}', '{"ar": "مبادرات للاتصالات السلكية واللاسلكية الخضراء في أفريقيا.", "en": "Initiatives for green telecommunications in Africa.", "fr": "Initiatives pour une télécommunication verte en Afrique.", "pt": "Iniciativas para as telecomunicações verdes em África."}', '{"ar": "وتؤدي تكنولوجيات المعلومات والاتصالات دورا رئيسيا في تحقيق خطة التنمية المستدامة لعام 2030", "en": "Information and communication technologies (ICTs) play a key role in achieving the 2030 Agenda for Sustainable Development.</p>", "fr": "<p>Les technologies de l''information et de la communication (TIC) jouent un rôle essentiel dans la réalisation du Programme 2030 pour le développement durable.</p>", "pt": "As tecnologias da informação e da comunicação (TIC) desempenham um papel fundamental na realização da Agenda para o Desenvolvimento Sustentável de 2030.</p>"}', '{"ar": "البيئة", "en": "environment", "fr": "environnement", "pt": "ambiente"}', 'UAT', 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=1200', '2026-04-27 02:14:17.863291+00', true, 'UAT Environnement', '5 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:19:57.364842+00', 'published', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000017', '{"ar": "التعاون الإقليمي: اتفاق الاتحاد الأوروبي", "en": "Regional cooperation: UAT-EU Agreement", "fr": "Coopération régionale : Accord UAT-UE", "pt": "Cooperação regional: Acordo UE-UAT"}', '{"ar": "اتفاق تعاون جديد بين محكمة التجارة الدولية والاتحاد الأوروبي.", "en": "New cooperation agreement between the UAT and the European Union.", "fr": "Nouvel accord de coopération entre l''UAT et l''Union Européenne.", "pt": "Novo acordo de cooperação entre a UAT e a União Europeia."}', '{"ar": "ويوفر الاتفاق 200 مليون يورو لمشاريع التوصيل في أفريقيا", "en": "The agreement provides €200 million for connectivity projects in Africa.</p>", "fr": "<p>L''accord prévoit un financement de 200 millions d''euros pour les projets de connectivité en Afrique.</p>", "pt": "O acordo prevê 200 milhões de euros para projectos de conectividade em África.</p>"}', '{"ar": "الشراكة", "en": "partnership", "fr": "partenariat", "pt": "parceria"}', 'UAT', 'https://eauxetforets.gouv.ci/sites/default/files/styles/page-actu-top/public/actualite/apv1.jpg?itok=Br6GV27r', '2026-04-26 22:14:17.863291+00', true, 'UAT Communication', '5 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:20:22.827543+00', 'published', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000018', '{"ar": "رقمنة الخدمات العامة", "en": "Digitalisation of public services", "fr": "Digitalisation des services publics", "pt": "Digitalização dos serviços públicos"}', '{"ar": "How the FSU finances administrative digitalization.", "en": "How the FSU finances administrative digitalization.", "fr": "Comment le FSU finance la digitalisation administrative.", "pt": "Como a FSU financia a digitalização administrativa."}', '{"ar": "وتتيح المشاريع الممولة من وحدة دعم البرامج رقمنة الخدمات العامة في المناطق الريفية", "en": "Projects funded by the FSU allow the digitization of public services in rural areas.</p>", "fr": "<p>Les projets financés par le FSU permettent la digitalisation des services publics dans les zones rurales.</p>", "pt": "Projetos financiados pela FSU permitem a digitalização de serviços públicos nas áreas rurais.</p>"}', '{"ar": "الحكومة الإلكترونية", "en": "e-government", "fr": "e-gouvernement", "pt": "administração em linha"}', 'UAT', 'https://images.theconversation.com/files/625175/original/file-20241011-15-350guy.jpg?ixlib=rb-4.1.0&rect=0%2C0%2C4243%2C2828&q=50&auto=format&w=768&h=512&fit=crop&dpr=2', '2026-04-27 00:14:17.863291+00', true, 'Bureau SADC', '6 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:20:13.235245+00', 'published', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000015', '{"ar": "أمن الشبكات: مبادئ توجيهية جديدة", "en": "Network Security: New Guidelines", "fr": "Sécurité des réseaux : Nouvelles directives", "pt": "Segurança da Rede: Novas Diretrizes"}', '{"ar": "مبادئ توجيهية بشأن أمن شبكات الاتصالات السلكية واللاسلكية.", "en": "UAT guidelines for telecommunications network security.", "fr": "Directives de l''UAT pour la sécurité des réseaux de télécommunications.", "pt": "Orientações da UAT para a segurança das redes de telecomunicações."}', '{"ar": "ينشر الاتحاد مبادئ توجيهية جديدة لتعزيز أمن الشبكات الوطنية للاتصالات السلكية واللاسلكية", "en": "<p>The UAT publishes new guidelines to enhance the cybersecurity of national telecommunications networks.</p>", "fr": "<p>L''UAT publie de nouvelles directives pour renforcer la cybersécurité des réseaux de télécommunications nationaux.</p>", "pt": "<p>A UAT publica novas diretrizes para melhorar a cibersegurança das redes nacionais de telecomunicações.</p>"}', '{"ar": "الأمن", "en": "security", "fr": "sécurité", "pt": "segurança"}', 'UAT', 'https://localhost-academy.com/wp-content/uploads/2022/10/responsabilites-dun-ingenieur-en-reseau-et-telecom-au-Cameroun.jpg', '2026-04-26 17:14:17.863291+00', true, 'UAT Technique', '7 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:20:44.910866+00', 'published', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000013', '{"ar": "المشورة الطبية عن بُعد في أفريقيا الريفية", "en": "Medical teleconsultation in rural Africa", "fr": "Téléconsultation médicale en Afrique rurale", "pt": "Teleconsulta médica na África rural"}', '{"ar": "كم ينقذ الإستشارة عن بعد الأرواح من خلال وحدة الدعم.", "en": "How teleconsultation saves lives through the FSU.", "fr": "Comment la téléconsultation sauve des vies grâce au FSU.", "pt": "Como a teleconsulta salva vidas através da FSU."}', '{"ar": "ويتيح نشر الهياكل الأساسية للاتصالات السلكية واللاسلكية في المناطق الريفية تطوير خدمات استشارية حيوية عن بعد", "en": "The deployment of telecommunications infrastructure in rural areas allows the development of vital tele-consultation services.</p>", "fr": "<p>Le déploiement d''infrastructures de télécommunication dans les zones rurales permet le développement de services de téléconsultation médicale vitaux.</p>", "pt": "A implantação de infra-estruturas de telecomunicações nas zonas rurais permite o desenvolvimento de serviços vitais de teleconsulta.</p>"}', '{"ar": "الصحة", "en": "health", "fr": "santé", "pt": "saúde"}', 'UAT', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=1200', '2026-04-26 12:14:17.863291+00', true, 'Dr. Aïcha Koné', '6 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:21:41.642395+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
