	('2cea13b2-ac53-4985-9a6a-2997bc0421a3', '{"en": "Annual meeting of Universal Service actors", "fr": "Réunion annuelle des acteurs du Service Universel"}', '{"en": "Major event organized in Egypt to discuss Universal Service Fund.", "fr": "Évènement majeur organisé en Égypte pour discuter de Fonds de Service Universel."}', '2026-10-18 19:33:40.687068+00', '2026-10-19 04:33:40.687068+00', '{"en": "Conference Center, Egypt", "fr": "Centre de Conférences, Égypte"}', 'workshop', 'upcoming', NULL, NULL, NULL, 'https://images.unsplash.com/photo-1540575861501-7cf05a4b125a?auto=format&fit=crop&q=80&w=800', NULL, true, '0ab2ec37-4634-4185-a417-2c62d24117e2', NULL, '2026-05-02 19:34:40.889923+00', '2026-05-02 19:34:40.889923+00', 'fr'),
	('d91c501f-952f-4b83-b0ce-35eac6894170', '{"en": "Webinar: Future of telecoms in Egypt", "fr": "Webinaire : Futur des télécoms en Égypte"}', '{"en": "Major event organized in Egypt to discuss E-education.", "fr": "Évènement majeur organisé en Égypte pour discuter de E-éducation."}', '2026-09-24 19:33:40.687081+00', '2026-09-27 01:33:40.687081+00', '{"en": "Conference Center, Egypt", "fr": "Centre de Conférences, Égypte"}', 'conference', 'upcoming', NULL, NULL, NULL, 'https://images.unsplash.com/photo-1540575861501-7cf05a4b125a?auto=format&fit=crop&q=80&w=800', NULL, true, '0ab2ec37-4634-4185-a417-2c62d24117e2', NULL, '2026-05-02 19:34:40.89555+00', '2026-05-02 19:34:40.89555+00', 'fr'),
