INSERT INTO "public"."faq_articles" ("id", "title", "content", "category", "sort_order", "is_published", "created_at", "updated_at") VALUES
	('8af8eedb-8982-49d7-a4b5-58aa8d8e2ae0', 'Comment créer un compte ?', 'Pour créer un compte, cliquez sur le bouton "S''inscrire" en haut à droite de la page. Remplissez le formulaire avec vos informations et validez votre adresse email.', 'general', 1, true, '2026-05-01 20:40:15.187828+00', '2026-05-01 20:40:15.187828+00'),
	('c4bb6850-ae09-4a50-b010-6a40f42c9bd6', 'Comment réinitialiser mon mot de passe ?', 'Cliquez sur "Mot de passe oublié" sur la page de connexion. Entrez votre adresse email et suivez les instructions envoyées par email.', 'account', 1, true, '2026-05-01 20:40:15.187828+00', '2026-05-01 20:40:15.187828+00'),
	('885b3511-acc7-4766-b489-c1a58b90193a', 'Qu''est-ce qu''une soumission FSU ?', 'Une soumission FSU (Forum des Syndicats Unifiés) est un document ou une information soumise par votre syndicat pour partage et validation.', 'fsu', 1, true, '2026-05-01 20:40:15.187828+00', '2026-05-01 20:40:15.187828+00'),
	('c2258c7b-55ad-4ba7-a5af-7904d061c9e0', 'Comment soumettre un document FSU ?', 'Allez dans la section FSU, cliquez sur "Nouvelle soumission", remplissez le formulaire et ajoutez vos pièces jointes.', 'fsu', 2, true, '2026-05-01 20:40:15.187828+00', '2026-05-01 20:40:15.187828+00');
