INSERT INTO "public"."forum_topics" ("id", "title", "content", "category_id", "created_by", "is_pinned", "is_locked", "is_public", "views", "status", "created_at", "updated_at") VALUES
	('ce297569-a6e5-4fd7-a90d-7e1c1bc7ef52', 'Bienvenue sur le forum USF-ADC', 'Bienvenue sur le forum public de la plateforme USF-ADC ! Cette plateforme est dédiée à la collaboration et à l''échange d''expériences entre les points focaux et les experts des Fonds de Service Universel en Afrique. N''hésitez pas à poser vos questions et à partager vos expertise.', '203c899e-f65d-4510-9343-aa651c7a6d47', NULL, true, false, true, 0, 'open', '2026-04-01 20:40:15.055375+00', '2026-04-01 20:40:15.055375+00'),
	('5183e56a-734a-4ebb-96ce-5d3458379b04', 'Stratégies de financement du FSU', 'Quelles sont les meilleures pratiques pour mobiliser les ressources du Fonds de Service Universel ? Partagez vos expériences et vos stratégies réussies.', '93b6011f-fded-4a8f-bf4d-fa3da1c19ecf', NULL, false, false, true, 0, 'open', '2026-04-06 20:40:15.055375+00', '2026-04-06 20:40:15.055375+00'),
	('1f454de9-7f51-4cfa-b445-d5f0677b1e9d', 'Problèmes d''accès à la plateforme', 'Je rencontre des difficultés pour me connecter à la plateforme. Comment puis-je résoudre ce problème ?', '203c899e-f65d-4510-9343-aa651c7a6d47', NULL, false, false, true, 0, 'solved', '2026-04-11 20:40:15.055375+00', '2026-04-13 20:40:15.055375+00'),
	('39dc4a9c-3b86-435c-bff5-c79b67b14881', 'Utilisation de la 5G pour le FSU', 'Avez-vous des projets de déploiement 5G utilisant les ressources du FSU ? Partagez les détails et les défis rencontrés.', '88550c34-a76c-4628-86bd-b129e7e0c173', NULL, false, false, true, 0, 'open', '2026-04-16 20:40:15.055375+00', '2026-04-16 20:40:15.055375+00'),
	('51b89531-33f5-4209-8e4f-c1f9d3580824', 'Connectivité rurale efficace', 'Quelle est la solution la plus rentable pour connecter les zones rurales ? Retours d''expérience bienvenus.', '88550c34-a76c-4628-86bd-b129e7e0c173', NULL, true, false, true, 0, 'open', '2026-04-21 20:40:15.055375+00', '2026-04-23 20:40:15.055375+00'),
	('61db7a56-b1ce-44dc-b7ae-f705ac8708e2', 'Gouvernance des FSU', 'Comment garantir une bonne gouvernance des Fonds de Service Universel au niveau national ?', 'd7ab1565-abf1-4d8c-814a-10601d1fffcf', NULL, false, false, true, 0, 'open', '2026-04-24 20:40:15.055375+00', '2026-04-24 20:40:15.055375+00'),
	('115dbcf8-e691-4a3c-8371-c4678bcc4a90', 'Partnership PPP dans le secteur télécom', 'Exemple de partenariats public-privé réussis pour les télécommunications en Afrique.', '93b6011f-fded-4a8f-bf4d-fa3da1c19ecf', NULL, false, false, true, 0, 'open', '2026-04-26 20:40:15.055375+00', '2026-04-27 20:40:15.055375+00'),
	('dacdf478-59aa-40b9-a6c3-53844e614637', 'Annonce : Nouvelle version de la plateforme', 'La version 2.0 de la plateforme USF-ADC est maintenant en ligne avec de nombreuses nouvelles fonctionnalités.', '203c899e-f65d-4510-9343-aa651c7a6d47', NULL, true, false, true, 0, 'open', '2026-04-28 20:40:15.055375+00', '2026-04-28 20:40:15.055375+00');
INSERT INTO "public"."forum_posts" ("id", "topic_id", "created_by", "content", "is_solution", "created_at", "updated_at") VALUES
	('644de92b-db34-4ffc-bd9a-066bb1b05c6f', '5183e56a-734a-4ebb-96ce-5d3458379b04', NULL, 'De mon expérience, il est crucial de combiner le financement gouvernemental avec les investissements privés pour maximiser les ressources du FSU.', false, '2026-04-07 20:40:15.055375+00', '2026-04-07 20:40:15.055375+00'),
	('f35803dc-7fa4-42c3-8455-71f6b03d4181', '5183e56a-734a-4ebb-96ce-5d3458379b04', NULL, 'Absolument ! Au Sénégal, nous avons utilisé un modèle mixte avec succès. Les opérateurs privés contribuent 30% du financement.', true, '2026-04-08 20:40:15.055375+00', '2026-04-08 20:40:15.055375+00'),
	('788f4ba8-6c29-44ee-9c70-cf1d5dd8e1ae', '1f454de9-7f51-4cfa-b445-d5f0677b1e9d', NULL, 'Avez-vous vérifié votre connexion internet ? Essayez de vider le cache de votre navigateur.', false, '2026-04-12 20:40:15.055375+00', '2026-04-12 20:40:15.055375+00'),
	('91e11824-0567-49af-8e54-a9f2fba0735f', '1f454de9-7f51-4cfa-b445-d5f0677b1e9d', NULL, 'Cela a résolu mon problème ! Merci beaucoup.', true, '2026-04-13 20:40:15.055375+00', '2026-04-13 20:40:15.055375+00'),
	('3c9600d3-b63a-45bc-83fa-d0d73f492aa4', '39dc4a9c-3b86-435c-bff5-c79b67b14881', NULL, 'Nous avons lancé un projet pilote 5G au Nigeria avec le soutien du FSU. Les résultats sont très prometteurs.', false, '2026-04-17 20:40:15.055375+00', '2026-04-17 20:40:15.055375+00'),
	('744ed448-8471-4ab3-98da-75e154cfafc4', '51b89531-33f5-4209-8e4f-c1f9d3580824', NULL, 'La fibre optique reste la solution la plus efficace pour les zones rurales, malgré les coûts initiaux élevés.', false, '2026-04-22 20:40:15.055375+00', '2026-04-22 20:40:15.055375+00'),
	('ea779950-27fc-45a7-a77b-9d8fadd9e943', '51b89531-33f5-4209-8e4f-c1f9d3580824', NULL, 'D''accord, mais avez-vous considéré les solutions par satellite pour les zones très reculées ?', false, '2026-04-23 20:40:15.055375+00', '2026-04-23 20:40:15.055375+00'),
	('bd9e1d9c-d73b-4079-85d4-3c60f91a7612', '115dbcf8-e691-4a3c-8371-c4678bcc4a90', NULL, 'Au Kenya, le partenariat PPP avec Safaricom a permis d''étendre la couverture mobile à 85% du pays.', false, '2026-04-27 20:40:15.055375+00', '2026-04-27 20:40:15.055375+00');
INSERT INTO "public"."fsu_agencies" ("id", "country_id", "dg_name", "dg_message", "dg_photo_url", "fsu_name", "agency_type", "created_at", "updated_at", "latitude", "longitude", "headquarters", "contact_phone", "contact_email") VALUES
	('3506f232-80e5-410e-8b61-9dd7fb7c7008', 'd3077782-c322-400c-8a2c-51b8fbd2a628', 'M. Gilles Thierry Beugré', '{"ar": "مرحبان¹ بكم في من صة USF-ADCA، ون¡ي ثمرة عمنž تعاون ي ن موذجي بين  دونžن ا انžأعضاء وشركائن ا انžتقن يين .", "en": "Welcome to the USF-ADCA platform, the fruit of exemplary collaborative work between our Member States and our technical partners. As director in charge of radiocommunications, I am convinced that optimal spectrum management and infrastructure deployment are keys to achieving our universal connectivity goals.", "fr": "Bienvenue sur la plateforme USF-ADCA, fruit d''un travail collaboratif exemplaire entre nos États membres et nos partenaires techniques. En tant que directeur en charge des radiocommunications, je suis convaincu que la gestion optimale du spectre et le déploiement des infrastructures sont les clés pour atteindre nos objectifs de connectivité universelle.", "pt": "Bem-vindo à plataforma USF-ADCA, fruto de um trabalho colaborativo exemplar entre os nossos Estados-Membros e os nosos parceiros técnicos."}', 'https://digitalmag.ci/wp-content/uploads/2025/03/Gilles-Beugre-DG-de-lANSUT-LIA-nous-aide-a-determiner-les-investissements-strategiques-dans-la-couverture-telecoms-en-Cote-dIvoire-.jpg', 'ANSUT', 'agency', '2026-05-01 20:40:15.494985+00', '2026-05-01 20:40:15.494985+00', 5.3484, -4.0305, 'Abidjan, Cocody Riviera', '+225 27 22 41 41 41', 'info@ansut.ci'),
	('4bc85f2a-7332-4a7d-8a66-77f617558dc5', 'd3077782-c322-400c-8a2c-51b8fbd2a628', 'M. Lakoun Ouattara', '{"ar": "انžتن ظيم ن¡و في قنžب تطوير انžاقتصاد انžرقمي.", "en": "Regulation is at the heart of the digital economy''s development. At ARTCI, we ensure that telecommunications infrastructure is accessible to all, while guaranteeing healthy competition for the benefit of populations.", "fr": "La régulation est au cœur du développement de l''économie numérique. À l''ARTCI, nous veillons à ce que les infrastructures de télécommunications soient accessibles à tous, tout en garantissant une saine concurrence pour le bénéfice des populations.", "pt": "A regulação está no centro do desenvolvimento da economia digital."}', 'https://www.artci.ci/images/stories/articles/IMG_0046.JPG', 'ARTCI', 'regulator', '2026-05-01 20:40:15.494985+00', '2026-05-01 20:40:15.494985+00', 5.3324, -4.0194, 'Abidjan, Marcory Anoumabo', '+225 27 20 34 43 00', 'artci@artci.ci'),
	('d41d725c-db7a-46dc-ada3-51941abe5b83', '7eee4f15-e529-4095-bc82-9f3aa33a3d4b', 'M. John Omo', '{"ar": "انžاتحاد انžأفريقي نžنžاتصانžات فخور بدعم ن¡ذن¡ انžمبادرة.", "en": "The African Telecommunications Union is proud to support this initiative. The harmonization of universal service policies across the continent is crucial to making Africa a prosperous digital society.", "fr": "L''Union Africaine des Télécommunications est fière de soutenir cette initiative. L''harmonisation des politiques de service universel à travers le continent est cruciale pour faire de l''Afrique une société numérique prospère.", "pt": "A União Africana de Telecomunicações orgulha-se de apoiar esta iniciativa."}', 'https://cdn.asp.events/CLIENT_Delinian_88510B86_A1E4_E5AE_E5572932A0001A1B/sites/itw-africa-2026/media/libraries/speakers/John-Omo.jpg', 'UAT (ATU)', 'institution', '2026-05-01 20:40:15.494985+00', '2026-05-01 20:40:15.494985+00', -1.2921, 36.8219, 'Nairobi, Kenya', '+254 20 232 2120', 'sg@atu-uat.africa'),
	('9e3343ef-be28-461b-9dd7-d99437264fa3', '4866a87c-4369-499c-acbb-587e06748d7a', 'Mme Fatou Diallo', '{"ar": "تنžتزم انžسن غانž بحزم بانžتحونž انžرقمي انžشامنž.", "en": "Senegal is resolutely committed to inclusive digital transformation. Our Universal Service Fund works every day so that every citizen can benefit from the opportunities offered by digital technology.", "fr": "Le Sénégal s''engage résolument dans la transformation numérique inclusive. Notre Fonds de Service Universel œuvre chaque jour pour que chaque citoyen puisse bénéficier des opportunités offertes par le numérique.", "pt": "O Senegal está resolutamente empenhado na transformação digital inclusiva."}', 'https://www.au-senegal.com/IMG/jpg/fatou1.jpg', 'FSU Sénégal', 'agency', '2026-05-01 20:40:15.494985+00', '2026-05-01 20:40:15.494985+00', 14.7167, -17.4677, 'Dakar, Sénégal', '+221 33 869 03 69', 'contact@fsu.sn'),
	('3a50453c-b9a0-48f9-9749-3a09b439d45f', 'd947b5eb-80bb-4265-afe4-adad4f36e4d4', 'M. Kwame Mensah', '{"ar": "من  خنžانž انžخدمة انžشامنžة، ن قوم بسد انžفجوة وتمكين  انžمجتمعات.", "en": "Through universal service, we are bridging the gap and empowering communities. Our platform is a testament to the power of collaboration and shared vision for a digitally inclusive Africa.", "fr": "Grâce au service universel, nous comblons le fossé et autonomisons les communautés. Notre plateforme témoigne du pouvoir de la collaboration et d''une vision partagée pour une Afrique numériquement inclusive.", "pt": "Através do serviço universal, estamos a colmatar a lacuna e a capacitar as comunidades."}', 'https://macdanenergy.com/professional-african-engineer-portrait.jpg', 'GIFEC Ghana', 'agency', '2026-05-01 20:40:15.494985+00', '2026-05-01 20:40:15.494985+00', 5.6037, -0.1870, 'Accra, Ghana', '+233 30 266 1111', 'info@gifec.gov.gh');
